public func tuningDatasetToVertex(
    apiClient: ApiClient,
    fromObject: [String: JSONValue],
    parentObject: inout [String: JSONValue],
    rootObject: [String: JSONValue]? = nil
) throws -> [String: JSONValue] {
    var toObject: [String: JSONValue] = [:]

    let discriminatorGcsUri = tuningMethodDiscriminator(rootObject)
    if discriminatorGcsUri == "SUPERVISED_FINE_TUNING" {
        let fromGcsUri = getValueByPath(.object(fromObject), ["gcsUri"])
        if case .null = fromGcsUri {} else {
            try setValueByPath(&parentObject, ["supervisedTuningSpec", "trainingDatasetUri"], fromGcsUri)
        }
    } else if discriminatorGcsUri == "PREFERENCE_TUNING" {
        let fromGcsUri = getValueByPath(.object(fromObject), ["gcsUri"])
        if case .null = fromGcsUri {} else {
            try setValueByPath(&parentObject, ["preferenceOptimizationSpec", "trainingDatasetUri"], fromGcsUri)
        }
    } else if discriminatorGcsUri == "DISTILLATION" {
        let fromGcsUri = getValueByPath(.object(fromObject), ["gcsUri"])
        if case .null = fromGcsUri {} else {
            try setValueByPath(&parentObject, ["distillationSpec", "promptDatasetUri"], fromGcsUri)
        }
    }

    let discriminatorVertexDatasetResource = tuningMethodDiscriminator(rootObject)
    if discriminatorVertexDatasetResource == "SUPERVISED_FINE_TUNING" {
        let fromVertexDatasetResource = getValueByPath(.object(fromObject), ["vertexDatasetResource"])
        if case .null = fromVertexDatasetResource {} else {
            try setValueByPath(&parentObject, ["supervisedTuningSpec", "trainingDatasetUri"], fromVertexDatasetResource)
        }
    } else if discriminatorVertexDatasetResource == "PREFERENCE_TUNING" {
        let fromVertexDatasetResource = getValueByPath(.object(fromObject), ["vertexDatasetResource"])
        if case .null = fromVertexDatasetResource {} else {
            try setValueByPath(&parentObject, ["preferenceOptimizationSpec", "trainingDatasetUri"], fromVertexDatasetResource)
        }
    } else if discriminatorVertexDatasetResource == "DISTILLATION" {
        let fromVertexDatasetResource = getValueByPath(.object(fromObject), ["vertexDatasetResource"])
        if case .null = fromVertexDatasetResource {} else {
            try setValueByPath(&parentObject, ["distillationSpec", "promptDatasetUri"], fromVertexDatasetResource)
        }
    }

    if case .null = getValueByPath(.object(fromObject), ["examples"]) {} else {
        throw GenAIError.runtime(
            "examples parameter is only supported in Gemini Developer API mode, not in Gemini Enterprise Agent Platform mode."
        )
    }

    return toObject
}

